@push('scripts')<script>const box=document.getElementById('landmarks');document.getElementById('addLandmark').addEventListener('click',()=>{box.insertAdjacentHTML('beforeend','<div class="landmark-row flex gap-2"><input name="landmarks[]" class="h-10 flex-1 rounded-xl border-slate-200 text-sm" placeholder="Near metro, college or hospital"><button type="button" class="remove-landmark rounded-xl bg-red-50 px-3 text-red-600"><i class="fas fa-trash"></i></button></div>')});box.addEventListener('click',e=>{const button=e.target.closest('.remove-landmark');if(button)button.closest('.landmark-row').remove()});const photos=document.getElementById('roomPhotos');photos.addEventListener('change',()=>{const preview=document.getElementById('photoPreview');const label=document.getElementById('photoSelection');preview.innerHTML='';const files=[...photos.files];label.textContent=files.length?`${files.length} new photo(s) selected. Save changes to upload.`:'No new photos selected.';files.slice(0,5).forEach(file=>{const image=document.createElement('img');image.src=URL.createObjectURL(file);image.className='h-20 w-28 rounded-xl border object-cover';preview.appendChild(image)})});</script>@endpush
